<script>
export default {
    name : 'ConfirmDialog',
    props:{

    },
    data(){
        return {
            showDialog  : false,
            icon        : null,
            iconClass   : null,
            title       : null,
            content     : null,
            close       : null,
            closeClass  : null,
            showClose   : null,
            save        : null,
            saveClass   : null,
            onClose     : null,
            onSave      : null,
            save2       : null,
            onSave2     : null,
            saveLoading : false,
            save2Loading: false
        }
    },
    watch :{
        showDialog : function(value){
            if( value == false){
                if( typeof this.onClose == 'function'){
                    this.onClose();
                }
                
                this.icon       = null
                this.iconClass  = null
                this.title      = null
                this.content    = null
                this.close      = null
                this.closeClass = null
                this.showClose  = null
                this.save       = null
                this.saveClass  = null
                this.onClose    = null
                this.onSave     = null
                this.save2      = null
                this.save2Class = null
                this.onSave2    = null
                this.saveLoading  =  false
                this.save2Loading =  false
            }
        }
    },
    methods:{
        show({ 
                icon= null ,
                iconClass = null, 
                title = null, 
                content = null, 
                close = null, 
                closeClass = null,
                showClose = true, 
                save = null, 
                saveClass = null, 
                onClose = null, 
                onSave = null,
                onSave2 = null,
                save2 = null,
                save2Class = null
            }){
            this.icon       = icon
            this.iconClass  = iconClass
            this.title      = title
            this.content    = content
            this.close      = close
            this.closeClass = closeClass
            this.showClose  = showClose
            this.save       = save
            this.saveClass  = saveClass
            this.onClose    = onClose
            this.onSave     = onSave
            this.save2      = save2
            this.save2Class = save2Class
            this.onSave2    = onSave2
            this.saveLoading = false
            this.save2Loading = false
            this.$nextTick(()=>{
                this.showDialog =  true
            })
        },
        handleClose(){
            if( this.saveLoading || this.save2Loading) return;
            this.showDialog = false;
        },
        handleSave(){
            if( typeof this.onSave == 'function'){
                this.saveLoading = true
                this.onSave().then(res=>{
                    this.showDialog = false;
                }, error => {
                    this.showDialog = false;
                });
            }else{
                this.showDialog = false;
            }
           
        },
        handleSave2(){
            if( typeof this.onSave2 == 'function'){
                this.save2Loading = true
                this.onSave2().then(res=>{
                    this.showDialog = false;
                }, error => {
                    this.showDialog = false;
                });
            }else{
                this.showDialog = false;
            }
            
        },
        clickaway(){
            if( this.saveLoading || this.save2Loading) return;
            if( this.showDialog ){
                this.showDialog = false;
            }
        }
    },
    mounted(){
        EventBus.$on('vue-show-confirm-dialog',  (config) => {
            this.show(config)
        })
    }
}
</script>
